import type { CareerQuestion } from "./social-worker-questions";

export const socialWorkerQuestionsBatch24: CareerQuestion[] = [
  { id: "sw-1176", stem: "A social worker uses CBT with a client who catastrophizes minor setbacks. Which technique is MOST appropriate to address this cognitive distortion?", options: ["Free association", "Decatastrophizing through guided questioning to evaluate the actual probability and impact of feared outcomes", "Flooding exposure", "Prescribing medication"], correctIndex: 1, rationale: "Decatastrophizing is a core CBT technique that helps clients evaluate the realistic probability and survivability of feared outcomes, directly targeting catastrophic thinking by examining evidence and developing balanced perspectives.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1177", stem: "In psychodynamic theory, what does 'transference' refer to?", options: ["Transferring a client to another provider", "The unconscious redirection of feelings from past significant relationships onto the therapist, which provides clinically useful information about the client's relational patterns", "A billing procedure", "Changing treatment modalities"], correctIndex: 1, rationale: "Transference is a central concept in psychodynamic theory where clients unconsciously project feelings, expectations, and relational patterns from early significant relationships onto the therapist, offering valuable insight into their interpersonal functioning and unresolved conflicts.", difficulty: 1, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1178", stem: "A family presents with an adolescent identified as the 'problem child.' From a family systems perspective, the social worker should FIRST:", options: ["Focus solely on the adolescent's behavior", "Assess the family system dynamics to understand how the adolescent's behavior functions within the broader family structure and relational patterns", "Remove the adolescent from the home", "Refer the adolescent for individual therapy only"], correctIndex: 1, rationale: "Family systems theory views the identified patient's symptoms as reflecting broader systemic dysfunction. Assessing the whole family system helps identify circular patterns, alliances, triangulation, and homeostatic mechanisms that maintain the presenting problem.", difficulty: 2, category: "Clinical Practice", topic: "family systems", questionType: "CASE_VIGNETTE" },
  { id: "sw-1179", stem: "Which DSM-5 criterion distinguishes substance use disorder from recreational use?", options: ["Any use of an illegal substance", "A maladaptive pattern of use leading to clinically significant impairment or distress, with at least two of eleven criteria met within a 12-month period", "Using a substance more than once", "Having a family history of addiction"], correctIndex: 1, rationale: "The DSM-5 defines substance use disorder by requiring at least two of eleven criteria (e.g., tolerance, withdrawal, craving, failed attempts to cut down, role impairment) within 12 months, distinguishing clinical disorder from non-problematic use through documented impairment or distress.", difficulty: 2, category: "Addictions & Substance Use", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1180", stem: "A mandated reporter suspects child neglect but has no physical evidence. What is the MOST appropriate action?", options: ["Wait until physical evidence is available", "File a report with child protective services because mandated reporters are required to report reasonable suspicion, not confirmed abuse", "Confront the parents directly", "Document concerns but take no action"], correctIndex: 1, rationale: "Mandated reporters are legally required to report reasonable suspicion of child abuse or neglect. The threshold is suspicion, not proof. The investigation is CPS's responsibility, and failure to report can result in legal consequences for the mandated reporter.", difficulty: 1, category: "Child & Family Services", topic: "child protection", questionType: "APPLIED_ETHICS" },
  { id: "sw-1181", stem: "An elderly client shows signs of financial exploitation by a caregiver. The social worker should FIRST:", options: ["Confront the caregiver immediately", "Assess the client's safety and cognitive capacity, document observations, and report to adult protective services while ensuring the client's immediate well-being", "Ignore it if the client doesn't complain", "Advise the client to change their bank accounts"], correctIndex: 1, rationale: "Elder abuse requires a systematic response: assess immediate safety and decision-making capacity, document objective observations, and report to adult protective services. Premature confrontation with the alleged perpetrator could escalate risk to the vulnerable adult.", difficulty: 2, category: "Assessment & Intervention Planning", topic: "elder abuse", questionType: "CASE_VIGNETTE" },
  { id: "sw-1182", stem: "A client recently lost their spouse and reports hearing the deceased's voice. The social worker should understand this as:", options: ["A psychotic symptom requiring immediate psychiatric referral", "A common and generally normal grief experience that may include auditory or visual perceptions of the deceased, particularly in the early months of bereavement", "Malingering for attention", "Evidence of a dissociative disorder"], correctIndex: 1, rationale: "Hearing or sensing the presence of a deceased loved one is a well-documented, common grief experience reported by 30-60% of bereaved individuals. It is generally not pathological and tends to be comforting rather than distressing, distinguishing it from psychotic hallucinations.", difficulty: 2, category: "Mental Health & Psychopathology", topic: "grief counseling", questionType: "CASE_VIGNETTE" },
  { id: "sw-1183", stem: "When working with a Native American client, what is the MOST culturally competent approach to assessment?", options: ["Apply standardized Western assessment tools without modification", "Incorporate understanding of the client's tribal-specific cultural values, healing traditions, historical trauma, and community context while collaborating with cultural consultants when appropriate", "Assume all Native Americans share the same cultural practices", "Avoid discussing culture to prevent stereotyping"], correctIndex: 1, rationale: "Cultural competency with Native American clients requires recognizing tribal diversity, understanding historical trauma's intergenerational impact, incorporating indigenous healing practices when desired by the client, and collaborating with cultural consultants to avoid cultural misunderstanding.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1184", stem: "A social worker discovers that a colleague is practicing while impaired by alcohol. The ethical obligation is to:", options: ["Cover for the colleague out of loyalty", "Address the concern by first speaking directly with the colleague if safe to do so, and report to the appropriate licensing board or supervisor if the impairment poses risk to clients", "Ignore it as a personal matter", "Tell all other staff members"], correctIndex: 1, rationale: "The NASW Code of Ethics requires social workers to address impaired colleagues. The first step is direct communication if feasible, followed by formal reporting through appropriate channels to protect clients from harm, balancing colleague support with client safety.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1185", stem: "According to the DSM-5, what is the primary distinguishing feature between major depressive disorder and persistent depressive disorder (dysthymia)?", options: ["Severity of symptoms only", "Duration—persistent depressive disorder requires depressed mood for most of the day, more days than not, for at least two years in adults, whereas MDD requires symptoms for at least two weeks", "The presence of suicidal ideation", "Response to medication"], correctIndex: 1, rationale: "The DSM-5 distinguishes these disorders primarily by duration: MDD requires a discrete episode of at least 2 weeks, while persistent depressive disorder requires chronic depressed mood for at least 2 years (1 year in children/adolescents). PDD may have lower symptom severity but its chronicity causes significant impairment.", difficulty: 3, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1186", stem: "In CBT, what is the purpose of a 'thought record'?", options: ["Recording the therapist's observations", "A structured tool for clients to identify, examine, and challenge automatic negative thoughts by documenting the situation, emotions, automatic thoughts, evidence for and against, and a balanced alternative thought", "A medical chart note", "A journaling exercise without structure"], correctIndex: 1, rationale: "Thought records are a core CBT intervention that teaches clients to systematically identify cognitive distortions, evaluate evidence objectively, and develop more balanced thinking patterns, building the skill of cognitive restructuring between sessions.", difficulty: 1, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1187", stem: "A client in substance use treatment reports cravings. Which CBT technique is MOST appropriate?", options: ["Psychoanalytic interpretation", "Identifying triggers and developing a coping plan that includes cognitive restructuring of urge-related thoughts, behavioral alternatives, and urge surfing techniques", "Encouraging moderate use", "Ignoring the cravings as temporary"], correctIndex: 1, rationale: "CBT for substance use disorders directly addresses cravings by helping clients identify triggers, challenge permission-giving thoughts, develop concrete coping strategies, and practice urge surfing—observing cravings as time-limited experiences without acting on them.", difficulty: 3, category: "Addictions & Substance Use", topic: "cognitive behavioral therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1188", stem: "From a psychodynamic perspective, what is the significance of 'resistance' in therapy?", options: ["The client is being deliberately difficult", "Resistance reflects unconscious defense mechanisms that protect the client from anxiety-provoking material, and exploring resistance provides valuable clinical information about underlying conflicts and defensive structures", "A sign therapy should be terminated", "Evidence of poor therapeutic alliance only"], correctIndex: 1, rationale: "In psychodynamic theory, resistance is understood as an unconscious protective mechanism rather than intentional obstruction. Analyzing resistance reveals the client's defensive structure and points toward the anxiety-provoking material that needs therapeutic attention.", difficulty: 3, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1189", stem: "A child welfare worker is assessing a family where domestic violence is present. What is the PRIORITY consideration?", options: ["Keeping the family together at all costs", "Assessing the immediate safety of all children and the non-offending parent, developing a safety plan, and connecting to domestic violence services while holding the perpetrator accountable", "Mediating between the parents", "Closing the case if violence hasn't been directed at children"], correctIndex: 1, rationale: "When domestic violence co-occurs with child welfare involvement, safety of children and the non-offending parent is the priority. Children exposed to domestic violence are at risk for direct harm and developmental trauma. Safety planning and perpetrator accountability are essential components.", difficulty: 3, category: "Child & Family Services", topic: "child protection", questionType: "PRIORITIZATION" },
  { id: "sw-1190", stem: "What is 'structural family therapy' and who developed it?", options: ["Therapy focusing only on family rules", "An approach developed by Salvador Minuchin that focuses on family organizational patterns, boundaries, subsystems, and hierarchies, with the therapist actively joining the family system and restructuring dysfunctional transactional patterns", "A form of individual therapy", "Only used in divorce situations"], correctIndex: 1, rationale: "Structural family therapy (Minuchin) examines and modifies the family's organizational structure—boundaries (rigid, diffuse, clear), subsystems (parental, sibling, spousal), hierarchies, and coalitions. The therapist joins the family, maps its structure, and uses techniques like enactment and boundary-making to restructure dysfunctional patterns.", difficulty: 3, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1191", stem: "A social worker at a hospice facility notices that a patient's family members are arguing about end-of-life care decisions. The BEST intervention is to:", options: ["Take sides with the most vocal family member", "Facilitate a family meeting to explore values, clarify the patient's wishes and advance directives, mediate conflicts, and support the family through anticipatory grief", "Avoid the conflict entirely", "Report the family to the ethics committee immediately"], correctIndex: 1, rationale: "Facilitating a family meeting allows the social worker to clarify the patient's wishes, address anticipatory grief that often underlies family conflict, mediate different perspectives, and ensure that care decisions honor the patient's autonomy and advance directives.", difficulty: 3, category: "Clinical Practice", topic: "grief counseling", questionType: "CASE_VIGNETTE" },
  { id: "sw-1192", stem: "What is 'motivational interviewing' (MI) and how does it address substance use ambivalence?", options: ["Telling clients they must stop using substances", "A collaborative, person-centered counseling approach that elicits and strengthens the client's own motivation for change by exploring and resolving ambivalence through open-ended questions, affirmations, reflections, and summaries", "A confrontational approach", "Only effective for alcohol use"], correctIndex: 1, rationale: "MI addresses ambivalence by evoking the client's own reasons for change rather than imposing external motivation. The spirit of MI (partnership, acceptance, compassion, evocation) and OARS techniques help clients explore discrepancies between their values and behaviors.", difficulty: 2, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "MCQ" },
  { id: "sw-1193", stem: "A social worker is counseling a recently widowed older adult who expresses guilt about feeling relief after a spouse's prolonged illness. The MOST therapeutic response is:", options: ["Tell the client they shouldn't feel that way", "Normalize the experience by acknowledging that relief after a prolonged caregiving burden is a common and understandable grief response that can coexist with love and sadness", "Refer for psychiatric evaluation", "Suggest the client wasn't truly devoted"], correctIndex: 1, rationale: "Relief after the death of a chronically ill loved one is a common grief response, especially following prolonged caregiving. Normalizing this emotion reduces guilt and shame, allowing the client to process the full complexity of their grief without self-judgment.", difficulty: 2, category: "Clinical Practice", topic: "grief counseling", questionType: "CASE_VIGNETTE" },
  { id: "sw-1194", stem: "In the DSM-5, what differentiates generalized anxiety disorder from normal worry?", options: ["Any amount of worry qualifies", "GAD involves excessive, difficult-to-control worry about multiple domains occurring more days than not for at least six months, with associated physical symptoms such as muscle tension, sleep disturbance, and fatigue causing clinically significant distress or impairment", "Only worry about health", "Worry triggered by a single event"], correctIndex: 1, rationale: "The DSM-5 criteria for GAD require excessive anxiety and worry about multiple events/activities, difficulty controlling the worry, duration of at least 6 months, and at least 3 of 6 somatic symptoms. The key distinctions from normal worry are the excessiveness, pervasiveness, uncontrollability, and associated functional impairment.", difficulty: 3, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1195", stem: "A social worker suspects elder self-neglect in a cognitively intact older adult who refuses services. What is the ethical consideration?", options: ["Force services on the client", "Respect the client's right to self-determination while thoroughly assessing capacity, documenting risks, providing education about consequences, and continuing to offer services, as competent adults have the right to make decisions others may view as unwise", "Close the case immediately", "Contact law enforcement"], correctIndex: 1, rationale: "When a cognitively intact adult refuses services, self-determination must be respected. The social worker's role is to ensure the client is making an informed decision, document the risks discussed, maintain the therapeutic relationship, and continue offering services without coercion.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "elder abuse", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1196", stem: "What is 'differentiation of self' in Bowen family systems theory?", options: ["Physical separation from family", "The capacity to maintain one's sense of self while remaining emotionally connected to others, reflecting the ability to distinguish between thinking and feeling and to function autonomously within an emotional system", "Cutting off from family entirely", "A measure of intelligence"], correctIndex: 1, rationale: "Differentiation of self (Bowen) refers to the ability to separate intellectual and emotional functioning, maintain a clear sense of self in relationships without being fused with or cut off from others, and manage anxiety within the family emotional system while remaining connected.", difficulty: 3, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1197", stem: "A client in early recovery from opioid use disorder asks about medication-assisted treatment (MAT). The social worker should:", options: ["Discourage MAT as replacing one drug with another", "Provide psychoeducation about evidence-based MAT options (methadone, buprenorphine, naltrexone), explain that MAT combined with counseling has the strongest evidence for opioid use disorder treatment, and support the client's informed decision-making", "Only recommend abstinence-based approaches", "Refer to a 12-step program instead"], correctIndex: 1, rationale: "MAT with methadone, buprenorphine, or naltrexone combined with psychosocial support is the gold standard treatment for opioid use disorder, reducing mortality by 50% or more. Social workers should provide accurate information and support informed decision-making without stigmatizing medication use.", difficulty: 3, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-1198", stem: "A social worker learns that a 15-year-old client is being sexually abused by a family member. What is the IMMEDIATE priority?", options: ["Gather more evidence before acting", "Ensure the child's immediate safety and file a mandated report with child protective services, as sexual abuse of a minor requires immediate reporting regardless of other considerations", "Ask the child to confront the abuser", "Wait for the next session to address it"], correctIndex: 1, rationale: "Sexual abuse of a minor requires immediate mandated reporting to CPS. The social worker must prioritize the child's safety, file the report promptly, document the disclosure accurately, and provide emotional support to the child while avoiding leading questions that could compromise the investigation.", difficulty: 2, category: "Child & Family Services", topic: "child protection", questionType: "PRIORITIZATION" },
  { id: "sw-1199", stem: "What is 'object relations theory' in psychodynamic practice?", options: ["Relating to physical objects", "A theoretical framework that examines how early relationships with primary caregivers create internalized mental representations (internal objects) that shape subsequent relationship patterns, self-concept, and emotional functioning throughout the lifespan", "A behavioral theory", "A group therapy model"], correctIndex: 1, rationale: "Object relations theory (Winnicott, Klein, Fairbairn) focuses on how internalized representations of early caregiver relationships shape personality structure, self-concept, and relational patterns. These 'internal objects' influence how individuals perceive and interact with others throughout life.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1200", stem: "A social worker is developing a culturally responsive treatment plan for an immigrant client experiencing depression. Which factor is MOST important to assess?", options: ["Only symptom severity", "The client's cultural conceptualization of distress, including cultural idioms of distress, explanatory models of illness, migration-related stressors, acculturation level, and available cultural support systems", "English proficiency only", "Length of time in the country"], correctIndex: 1, rationale: "Cultural conceptualizations of distress (DSM-5 Cultural Formulation Interview) are essential because different cultures express and understand psychological suffering differently. Assessment must include migration stressors, acculturation stress, cultural identity, and the client's own framework for understanding their experience.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1201", stem: "In CBT for depression, behavioral activation involves:", options: ["Resting until the depression lifts", "Systematically scheduling pleasurable and mastery activities to counteract withdrawal and avoidance patterns, recognizing that changes in behavior can lead to improvements in mood and cognition", "Only discussing feelings", "Medication management"], correctIndex: 1, rationale: "Behavioral activation is a core CBT component for depression based on the principle that depression leads to withdrawal, which reduces positive reinforcement, worsening mood. Scheduling activities increases engagement, provides positive experiences, and breaks the depression-inactivity cycle.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1202", stem: "A social worker in a hospital setting discovers that a patient's advance directive conflicts with the family's wishes. The social worker should:", options: ["Follow the family's wishes", "Advocate for the patient's documented wishes as expressed in the advance directive, educate the family about the legal and ethical importance of honoring the patient's autonomy, and facilitate communication between medical staff and family", "Ignore the advance directive", "Let the physician decide alone"], correctIndex: 1, rationale: "Advance directives are legal documents expressing the patient's autonomous wishes. The social worker's role is to advocate for the patient's self-determination, help the family understand the ethical and legal basis for honoring these wishes, and facilitate difficult conversations about end-of-life care.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1203", stem: "What is 'triangulation' in family systems theory?", options: ["A research methodology", "A relational pattern where two family members manage tension in their relationship by involving a third person, creating a three-person system that stabilizes the dyad but typically creates problems for the triangulated member", "A geometric concept only", "A communication technique"], correctIndex: 1, rationale: "Triangulation (Bowen) occurs when a two-person emotional system is unstable and recruits a third person to diffuse anxiety. Common examples include a parent involving a child in marital conflict. While it temporarily reduces dyadic tension, it burdens the third party and prevents direct resolution of the original conflict.", difficulty: 3, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1204", stem: "A client diagnosed with PTSD avoids discussing traumatic memories. From a trauma-informed perspective, the social worker should:", options: ["Force the client to recount the trauma immediately", "Respect the client's pace while establishing safety and trust, using grounding techniques, psychoeducation about trauma responses, and gradually building the client's capacity to approach traumatic material when they are ready", "Terminate treatment due to resistance", "Focus exclusively on present-day problems without addressing trauma"], correctIndex: 1, rationale: "Trauma-informed care prioritizes safety, trustworthiness, and collaboration. Forcing premature trauma processing can retraumatize clients. The phased approach (safety/stabilization first, then processing, then integration) ensures clients develop sufficient coping resources before addressing traumatic memories.", difficulty: 3, category: "Trauma-Informed Care", topic: "cognitive behavioral therapy", questionType: "CASE_VIGNETTE" },
  { id: "sw-1205", stem: "Which of the following is an example of 'countertransference' in psychodynamic therapy?", options: ["The client projecting feelings onto the therapist", "The therapist experiencing strong protective feelings toward a client that mirror their own unresolved parenting issues, which may influence clinical judgment and treatment decisions", "A standard emotional response to a client's story", "Setting appropriate boundaries"], correctIndex: 1, rationale: "Countertransference refers to the therapist's emotional reactions to the client that are rooted in the therapist's own unresolved issues. Recognizing and managing countertransference through supervision and self-awareness is essential to maintaining objectivity and effective treatment.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-1206", stem: "A social worker is working with a family where the parents have different cultural backgrounds and conflicting parenting styles. The BEST approach is to:", options: ["Side with one parent's cultural approach", "Facilitate dialogue that explores how each parent's cultural values inform their parenting, identify shared goals for the children, and help the couple negotiate a parenting approach that integrates both cultural perspectives", "Impose evidence-based parenting standards", "Refer to a cultural specialist and close the case"], correctIndex: 1, rationale: "Culturally competent family work with bicultural families involves understanding each parent's cultural framework, validating both perspectives, helping identify shared parenting values, and facilitating integration rather than choosing one cultural approach over another.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1207", stem: "What are the DSM-5 criteria for alcohol use disorder?", options: ["Any alcohol consumption", "A problematic pattern of alcohol use leading to clinically significant impairment or distress, manifested by at least two of eleven criteria within a 12-month period, with severity rated as mild (2-3), moderate (4-5), or severe (6+) criteria", "Only physical dependence", "Binge drinking on weekends"], correctIndex: 1, rationale: "The DSM-5 uses a dimensional approach with 11 criteria for alcohol use disorder, combining the previous abuse/dependence distinction into a single disorder rated by severity. This approach better captures the spectrum of problematic alcohol use patterns.", difficulty: 2, category: "Addictions & Substance Use", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1208", stem: "A social worker receives a subpoena for client records. The FIRST step should be:", options: ["Immediately release all records", "Consult with the agency's legal counsel, inform the client, and determine whether to assert privilege, negotiate limited release, or seek a protective order, as a subpoena does not automatically override confidentiality", "Destroy the records", "Ignore the subpoena"], correctIndex: 1, rationale: "A subpoena is a legal request, not a court order. Social workers should consult legal counsel, inform the client, review privilege protections, and explore options including asserting privilege, seeking a protective order, or negotiating limited disclosure to protect client confidentiality to the greatest extent possible.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "APPLIED_ETHICS" },
  { id: "sw-1209", stem: "In Kübler-Ross's model, what is the significance of the 'bargaining' stage of grief?", options: ["It indicates pathological grief", "It represents the griever's attempt to negotiate with a higher power or fate to reverse or delay the loss, often involving 'if only' or 'what if' statements that reflect the struggle to find meaning and regain control", "It means the client is manipulative", "It only occurs in terminal illness"], correctIndex: 1, rationale: "Bargaining in Kübler-Ross's model reflects the human need for control in the face of loss. It often involves magical thinking, guilt-laden 'if only' statements, and attempts to negotiate outcomes. While the stage model is not linear or universal, bargaining represents a common coping mechanism during grief.", difficulty: 2, category: "Mental Health & Psychopathology", topic: "grief counseling", questionType: "MCQ" },
  { id: "sw-1210", stem: "A social worker suspects Munchausen syndrome by proxy (factitious disorder imposed on another) in a pediatric case. The appropriate response is to:", options: ["Confront the parent immediately", "Document observations carefully, consult with the medical team, and report to child protective services, as this form of child abuse requires a coordinated multidisciplinary response to ensure the child's safety", "Dismiss the suspicion as unlikely", "Conduct therapy with the parent first"], correctIndex: 1, rationale: "Factitious disorder imposed on another is a form of child abuse requiring careful, coordinated intervention. Direct confrontation without proper coordination can lead to the perpetrator fleeing, escalating harm, or destroying evidence. A multidisciplinary approach with CPS involvement is essential for child safety.", difficulty: 4, category: "Child & Family Services", topic: "child protection", questionType: "PRIORITIZATION" },
  { id: "sw-1211", stem: "What is the 'biopsychosocial model' in social work assessment?", options: ["Only assessing biological factors", "A comprehensive assessment framework that examines the interplay of biological factors (genetics, health, neurochemistry), psychological factors (cognition, emotion, behavior, personality), and social factors (relationships, culture, environment, socioeconomic status) in understanding a client's presenting issues", "A medical model approach", "A theoretical orientation for therapy"], correctIndex: 1, rationale: "The biopsychosocial model (Engel) provides a holistic assessment framework central to social work practice. It recognizes that human functioning results from the complex interaction of biological, psychological, and social factors, aligning with social work's person-in-environment perspective.", difficulty: 1, category: "Assessment & Intervention Planning", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1212", stem: "A client with borderline personality disorder frequently calls the social worker after hours during crises. The MOST appropriate response is:", options: ["Answer every call regardless of boundaries", "Establish clear expectations about between-session contact, develop a crisis safety plan with the client, provide emergency resources, and address the pattern therapeutically while maintaining consistent, predictable boundaries", "Refuse all after-hours contact", "Transfer the client to another provider"], correctIndex: 1, rationale: "Clients with BPD benefit from consistent, predictable boundaries that are established collaboratively. A comprehensive approach includes a safety plan, emergency resources, clear expectations about contact, and therapeutic processing of boundary-testing behavior within sessions.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-1213", stem: "Which ethical principle is MOST relevant when a social worker must break confidentiality to report child abuse?", options: ["Beneficence only", "The duty to protect vulnerable individuals overrides confidentiality when there is a legal mandate to report, reflecting the ethical hierarchy where protection of life and safety takes precedence over privacy", "Client self-determination", "Maintaining the therapeutic relationship"], correctIndex: 1, rationale: "When ethical principles conflict, social workers follow an ethical hierarchy where protection of life and safety (especially of vulnerable populations like children) takes precedence over confidentiality. Mandated reporting laws codify this ethical priority into legal requirements.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1214", stem: "What is 'complicated grief' (prolonged grief disorder) in the DSM-5?", options: ["Any grief lasting more than two weeks", "A condition characterized by persistent, intense yearning and preoccupation with the deceased, marked difficulty accepting the death, identity disruption, and significant functional impairment persisting for at least 12 months in adults after the loss", "Normal sadness after a loss", "Only occurs after sudden deaths"], correctIndex: 1, rationale: "Prolonged grief disorder (new to DSM-5-TR) is characterized by intense yearning, preoccupation with the deceased, identity disruption, emotional numbness, and functional impairment lasting at least 12 months. It is distinct from normal grief and depression, requiring specific clinical attention.", difficulty: 4, category: "Mental Health & Psychopathology", topic: "grief counseling", questionType: "MCQ" },
  { id: "sw-1215", stem: "A social worker notices that a client consistently intellectualizes painful emotions. From a psychodynamic perspective, this represents:", options: ["Good coping skills", "A defense mechanism where the client uses abstract thinking and reasoning to distance from the emotional impact of difficult experiences, potentially limiting therapeutic progress by avoiding affective engagement", "Superior intelligence", "Readiness for advanced therapy"], correctIndex: 1, rationale: "Intellectualization is a defense mechanism that keeps threatening emotions at a cognitive distance. While higher-order defenses like intellectualization are more adaptive than primitive defenses, excessive reliance on them in therapy can prevent the emotional processing necessary for therapeutic change.", difficulty: 3, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-1216", stem: "What is the CAGE questionnaire used for in social work practice?", options: ["Assessing cognitive impairment", "A brief four-question screening tool for problematic alcohol use that asks about Cutting down, Annoyance at criticism about drinking, Guilty feelings about drinking, and using alcohol as an Eye-opener, with two or more positive responses suggesting further assessment is needed", "Evaluating housing stability", "Screening for depression"], correctIndex: 1, rationale: "The CAGE questionnaire is a widely used, validated brief screening tool for alcohol problems. Its simplicity (four yes/no questions) makes it practical for various social work settings. Two or more positive responses indicate a high likelihood of an alcohol use disorder requiring comprehensive assessment.", difficulty: 1, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "MCQ" },
  { id: "sw-1217", stem: "A school social worker identifies a pattern of bullying targeting LGBTQ+ students. The MOST comprehensive intervention includes:", options: ["Counseling only the bullied students", "Implementing a multi-level approach that includes individual support for affected students, schoolwide anti-bullying policy development, staff training on LGBTQ+ inclusivity, and establishing a Gay-Straight Alliance or similar support group", "Punishing bullies without systemic change", "Advising LGBTQ+ students to be less visible"], correctIndex: 1, rationale: "Effective anti-bullying interventions require systemic change at multiple levels: individual support, peer education, policy development, staff training, and creating an inclusive school culture. Focusing solely on individual counseling fails to address the environmental factors that enable bullying.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1218", stem: "What is 'ego psychology' and its relevance to clinical social work?", options: ["A theory about narcissism", "A psychodynamic framework that emphasizes the adaptive, reality-oriented functions of the ego—including defense mechanisms, object relations, judgment, and reality testing—providing a foundation for assessment of ego functioning and strengths-based clinical intervention", "A purely behavioral approach", "Only relevant to personality disorders"], correctIndex: 1, rationale: "Ego psychology (Hartmann, Anna Freud) expanded psychoanalytic theory to focus on the ego's adaptive functions. It provides social workers with a framework for assessing ego strengths (reality testing, judgment, impulse control, defenses) and planning interventions that support and build on existing ego capacities.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1219", stem: "A social worker is conducting a home visit and observes unsanitary conditions but no immediate danger to the children. The BEST approach is:", options: ["Remove the children immediately", "Assess the family's understanding of the impact, explore barriers to maintaining the home (poverty, depression, disability), connect with concrete services (housing assistance, cleaning support), and monitor progress while documenting observations", "Ignore the conditions", "Report to law enforcement"], correctIndex: 1, rationale: "Unsanitary conditions without immediate danger require assessment of contributing factors before intervention. Poverty, mental health issues, and lack of resources often underlie neglectful conditions. A strengths-based approach connects families to concrete services while monitoring child welfare.", difficulty: 3, category: "Child & Family Services", topic: "child protection", questionType: "CASE_VIGNETTE" },
  { id: "sw-1220", stem: "In cognitive behavioral therapy, what is 'cognitive restructuring'?", options: ["Brain surgery", "A systematic process of identifying, evaluating, and modifying maladaptive thought patterns and core beliefs by examining evidence, generating alternative interpretations, and developing more balanced, realistic cognitive frameworks", "Changing the therapy setting", "Memory enhancement techniques"], correctIndex: 1, rationale: "Cognitive restructuring is the central change mechanism in CBT. It teaches clients to identify cognitive distortions (all-or-nothing thinking, catastrophizing, mind reading), examine evidence, and develop more balanced thoughts, leading to improved emotional and behavioral responses.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1221", stem: "A social worker is working with a client who experienced childhood sexual abuse and now has difficulty with intimate relationships. Which theoretical framework BEST explains this connection?", options: ["Behavioral conditioning only", "Attachment theory and trauma theory, which explain how early relational trauma disrupts the development of secure attachment patterns, creating difficulties with trust, intimacy, emotional regulation, and vulnerability in adult relationships", "Genetic determinism", "Purely cognitive distortions"], correctIndex: 1, rationale: "Childhood sexual abuse by a caregiver or trusted person fundamentally disrupts attachment security. Trauma theory explains the neurobiological and psychological impacts, while attachment theory explains how disrupted early relationships create working models that affect adult intimacy, trust, and relational patterns.", difficulty: 4, category: "Trauma-Informed Care", topic: "psychodynamic theory", questionType: "CASE_VIGNETTE" },
  { id: "sw-1222", stem: "What is 'harm reduction' in the context of substance use treatment?", options: ["Enabling drug use", "A pragmatic public health approach that acknowledges the reality of substance use and focuses on minimizing negative consequences without requiring abstinence as a precondition for treatment, including strategies like needle exchange, naloxone distribution, and managed alcohol programs", "A permissive attitude toward drugs", "Only for people who refuse treatment"], correctIndex: 1, rationale: "Harm reduction is an evidence-based approach that meets people where they are, reducing the health and social harms associated with substance use. It includes practical strategies (needle exchange, naloxone, drug checking) and reduces barriers to treatment engagement.", difficulty: 2, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "MCQ" },
  { id: "sw-1223", stem: "A social worker encounters a dual relationship situation where a client is also a member of the same small faith community. The MOST ethical approach is:", options: ["Immediately terminate the therapeutic relationship", "Discuss the dual relationship openly with the client, assess potential for harm, establish clear boundaries between the professional and community roles, document the situation, and seek consultation or supervision", "Pretend the outside relationship doesn't exist", "Leave the faith community"], correctIndex: 1, rationale: "In small communities, dual relationships may be unavoidable. The ethical response involves transparency, boundary clarity, informed consent, ongoing monitoring for potential harm, and consultation. Immediate termination may not serve the client's best interest if alternative providers are unavailable.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1224", stem: "What is the 'diathesis-stress model' of mental illness?", options: ["Mental illness is purely genetic", "A theoretical framework proposing that mental disorders result from the interaction between a predisposing vulnerability (diathesis—genetic, biological, or psychological) and environmental stressors, with the disorder manifesting when stress exceeds the individual's threshold of vulnerability", "Only stress causes mental illness", "Mental illness is a choice"], correctIndex: 1, rationale: "The diathesis-stress model integrates biological and environmental factors, explaining why some individuals develop mental illness under stress while others do not. It informs prevention (reducing stressors) and treatment (building resilience and coping to manage vulnerability).", difficulty: 3, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1225", stem: "A social worker is assessing an older adult who shows signs of cognitive decline but insists on managing their own finances. How should the social worker balance autonomy and safety?", options: ["Immediately assume power of attorney", "Conduct a thorough cognitive and functional assessment, explore the client's current financial management abilities, identify specific risks, involve the client in developing safeguards, and consider graduated interventions that preserve maximum autonomy while protecting against exploitation", "Respect the client's wishes without assessment", "Report to adult protective services immediately"], correctIndex: 1, rationale: "Balancing autonomy and safety requires a nuanced approach: thorough assessment of decision-making capacity, identification of specific risks, collaborative problem-solving with the client, and graduated interventions (bill-pay services, representative payee, joint accounts) that maintain the greatest possible autonomy while mitigating harm.", difficulty: 4, category: "Assessment & Intervention Planning", topic: "elder abuse", questionType: "CASE_VIGNETTE" },
  { id: "sw-1226", stem: "What is 'parallel process' in clinical supervision?", options: ["Supervising two people at once", "A phenomenon where the dynamics occurring in the therapeutic relationship are unconsciously replicated in the supervisory relationship, providing the supervisor with valuable information about the therapeutic process and the supervisee's experience with the client", "Running groups in parallel", "A billing structure"], correctIndex: 1, rationale: "Parallel process is a psychodynamic concept in supervision where relational patterns between client and therapist are mirrored between therapist and supervisor. Recognizing parallel process helps supervisors identify therapeutic dynamics and model effective responses.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1227", stem: "A social worker is leading a grief support group. One member monopolizes sessions. The BEST intervention is:", options: ["Allow it to maintain group harmony", "Address the behavior therapeutically by gently redirecting, exploring the meaning behind the monopolizing behavior, setting group norms about shared participation, and inviting quieter members to share while validating the active member's contributions", "Remove the member from the group", "Ignore the behavior"], correctIndex: 1, rationale: "Monopolizing behavior in grief groups may reflect anxiety, a need for control, or difficulty tolerating others' pain. Therapeutic group leadership addresses the behavior directly but compassionately, sets norms for equitable participation, and uses the interaction as therapeutic material.", difficulty: 3, category: "Clinical Practice", topic: "grief counseling", questionType: "CASE_VIGNETTE" },
  { id: "sw-1228", stem: "What are 'core beliefs' in cognitive behavioral therapy?", options: ["Religious beliefs", "Deep, fundamental assumptions about the self, others, and the world that develop from early life experiences and filter all subsequent information processing, often operating as absolute, overgeneralized rules such as 'I am worthless' or 'The world is dangerous'", "Current opinions about therapy", "Therapeutic techniques"], correctIndex: 1, rationale: "Core beliefs (schemas) in CBT are the deepest level of cognition, formed through early experiences. They generate automatic thoughts and intermediate beliefs (rules, attitudes, assumptions) that maintain psychopathology. Identifying and modifying core beliefs is the focus of schema-focused CBT approaches.", difficulty: 3, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1229", stem: "A social worker learns that a 10-year-old client is left unsupervised after school daily while the single parent works. What should the social worker consider FIRST?", options: ["Immediately file a neglect report", "Assess the totality of circumstances including the child's maturity, neighborhood safety, duration of unsupervised time, available resources, state-specific age guidelines, cultural context, and the parent's efforts to ensure the child's safety before determining next steps", "Advise the parent to quit their job", "Do nothing as the parent is working"], correctIndex: 1, rationale: "Unsupervised children require contextual assessment rather than automatic reporting. Factors include the child's developmental maturity, state laws on minimum supervision age, environmental safety, duration, parent's resourcefulness, and cultural norms. The goal is connecting the family with resources (afterschool programs) while ensuring child safety.", difficulty: 3, category: "Child & Family Services", topic: "child protection", questionType: "CASE_VIGNETTE" },
  { id: "sw-1230", stem: "In Erikson's psychosocial development theory, the crisis of 'generativity vs. stagnation' occurs during:", options: ["Adolescence", "Middle adulthood (approximately ages 40-65), when individuals focus on contributing to the next generation through parenting, mentoring, community involvement, or creative work, with failure to do so resulting in feelings of stagnation and self-absorption", "Early childhood", "Late adulthood"], correctIndex: 1, rationale: "Erikson's seventh stage, generativity vs. stagnation, occurs in middle adulthood. Successful resolution involves caring for and guiding the next generation. Understanding this stage helps social workers contextualize midlife challenges, career transitions, and the search for meaning and legacy.", difficulty: 1, category: "Human Development", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1231", stem: "A social worker is treating a client with co-occurring PTSD and alcohol use disorder. Which treatment approach has the STRONGEST evidence base?", options: ["Treating one disorder completely before addressing the other", "Integrated treatment that addresses both disorders simultaneously, such as Seeking Safety or concurrent prolonged exposure with substance use treatment, recognizing that the disorders are interconnected and mutual maintaining", "Only 12-step meetings", "Detox followed by trauma therapy with no overlap"], correctIndex: 1, rationale: "Research supports integrated treatment for co-occurring PTSD and substance use disorders. Sequential treatment often fails because each disorder maintains the other (substance use manages PTSD symptoms; trauma symptoms trigger relapse). Seeking Safety and integrated CBT approaches address both simultaneously.", difficulty: 4, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-1232", stem: "What is the concept of 'intersectionality' and why is it important in social work?", options: ["A traffic pattern", "A framework developed by Kimberlé Crenshaw recognizing that individuals hold multiple social identities (race, gender, class, sexuality, disability) that intersect to create unique experiences of privilege and oppression that cannot be understood by examining any single identity in isolation", "Only about race and gender", "An academic theory with no practical application"], correctIndex: 1, rationale: "Intersectionality is essential to social work because it explains how multiple forms of oppression interact to create unique experiences. A Black woman's experience differs from examining race and gender separately. This framework ensures comprehensive, nuanced assessment and culturally responsive intervention.", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "MCQ" },
  { id: "sw-1233", stem: "A social worker is conducting a suicide risk assessment. Which factor is the STRONGEST predictor of suicide completion?", options: ["Passive suicidal ideation", "A previous suicide attempt, particularly one that was medically serious, used a lethal method, and occurred within the past year, combined with current hopelessness and access to lethal means", "Expressing sadness", "Talking about death in general"], correctIndex: 1, rationale: "Previous suicide attempts are the single strongest predictor of future suicide completion. Risk increases with recency, lethality of prior attempts, and the combination of current hopelessness, intent, plan specificity, and access to means. Comprehensive risk assessment considers all these factors.", difficulty: 3, category: "Crisis Intervention", topic: "DSM-5 diagnoses", questionType: "PRIORITIZATION" },
  { id: "sw-1234", stem: "What is 'family homeostasis' in systems theory?", options: ["A medical condition", "The tendency of a family system to maintain its current patterns and equilibrium, even when those patterns are dysfunctional, through feedback loops that resist change and maintain the status quo of family interactions", "A type of therapy", "Financial stability in families"], correctIndex: 1, rationale: "Family homeostasis explains why families resist change even when current patterns cause suffering. The system's self-regulating mechanisms maintain equilibrium through negative feedback loops. Understanding homeostasis helps social workers anticipate resistance and strategize interventions that shift the entire system.", difficulty: 3, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1235", stem: "A client presents with sudden onset of intense fear, pounding heart, shortness of breath, and a sense of impending doom. These symptoms are MOST consistent with:", options: ["A heart attack", "A panic attack, characterized by an abrupt surge of intense fear or discomfort reaching a peak within minutes, accompanied by four or more physical and cognitive symptoms as defined in the DSM-5", "An anxiety disorder only", "A psychotic episode"], correctIndex: 1, rationale: "The DSM-5 defines a panic attack as an abrupt surge of intense fear reaching a peak within minutes, with at least 4 of 13 symptoms (palpitations, sweating, trembling, shortness of breath, choking, chest pain, nausea, dizziness, derealization, fear of losing control, fear of dying, numbness, chills/hot flashes). Medical causes should also be ruled out.", difficulty: 2, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1236", stem: "A social worker is providing crisis intervention to a client who has just experienced a natural disaster. The FIRST priority is:", options: ["Processing the emotional impact", "Ensuring the client's immediate physical safety, basic needs (shelter, food, water), and connection to emergency resources before addressing psychological needs", "Beginning trauma-focused therapy", "Administering psychological assessments"], correctIndex: 1, rationale: "In crisis intervention following a disaster, Maslow's hierarchy applies: physiological and safety needs must be met before psychological intervention. The Psychological First Aid model emphasizes practical assistance, safety, comfort, connection, and information before processing emotional reactions.", difficulty: 1, category: "Crisis Intervention", topic: "cognitive behavioral therapy", questionType: "PRIORITIZATION" },
  { id: "sw-1237", stem: "What is 'projective identification' in psychodynamic theory?", options: ["A diagnostic test", "An unconscious process where an individual projects unacceptable aspects of themselves onto another person and then interacts with that person in a way that elicits the projected feelings, creating a self-fulfilling interpersonal dynamic", "A personality assessment tool", "A conscious manipulation tactic"], correctIndex: 1, rationale: "Projective identification (Klein) goes beyond projection: the individual not only projects unwanted feelings onto another but interacts in ways that pressure the other to experience and enact those feelings. Understanding this helps therapists recognize when they are being pulled into enacting client dynamics.", difficulty: 5, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1238", stem: "A social worker is developing a relapse prevention plan with a client recovering from stimulant use disorder. Which component is MOST essential?", options: ["Promising never to use again", "Identifying high-risk situations, developing specific coping strategies for each, building a support network, recognizing early warning signs of relapse, and creating an emergency action plan", "Avoiding all social situations", "Relying solely on willpower"], correctIndex: 1, rationale: "Marlatt's relapse prevention model identifies high-risk situations, seemingly irrelevant decisions, and coping deficits as relapse precursors. An effective plan is specific, personalized, addresses cognitive and behavioral components, builds social support, and includes contingency plans for lapses.", difficulty: 3, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-1239", stem: "A social worker must decide whether to disclose a client's HIV status to the client's sexual partner. This situation involves which ethical tension?", options: ["Only legal considerations", "The tension between the duty to protect third parties from serious harm (duty to warn) and the obligation to maintain client confidentiality, requiring careful consideration of state laws, professional guidelines, and efforts to encourage voluntary disclosure first", "No ethical issues exist", "Only the client's rights matter"], correctIndex: 1, rationale: "HIV disclosure situations exemplify the tension between confidentiality and duty to protect. The social worker should first encourage the client to disclose voluntarily, consult state-specific laws regarding HIV disclosure obligations, seek supervision, and follow the ethical decision-making process balancing competing obligations.", difficulty: 5, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1240", stem: "What is 'dialectical behavior therapy' (DBT) and for whom was it originally developed?", options: ["A form of psychoanalysis", "A comprehensive cognitive-behavioral treatment originally developed by Marsha Linehan for chronically suicidal individuals with borderline personality disorder, integrating acceptance and change strategies through individual therapy, skills training groups, phone coaching, and a consultation team", "Only for depression", "A brief therapy model"], correctIndex: 1, rationale: "DBT was specifically designed for borderline personality disorder and chronic suicidality. Its dialectical framework balances acceptance and change through four skill modules (mindfulness, distress tolerance, emotion regulation, interpersonal effectiveness) delivered via individual therapy, skills groups, phone coaching, and therapist consultation.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1241", stem: "A social worker working in child protective services receives a referral for a family from a culture that practices physical discipline. How should the worker approach this case?", options: ["Automatically classify it as abuse", "Conduct a thorough assessment that distinguishes between culturally normative discipline practices and practices that cause harm to the child, using objective indicators of injury while remaining culturally sensitive and educating about legal standards", "Ignore concerns due to cultural differences", "Remove the children preemptively"], correctIndex: 1, rationale: "Cultural competency in child protection requires distinguishing between discipline practices and abuse while maintaining child safety as the priority. The social worker must objectively assess for harm, educate families about legal standards, and offer culturally responsive alternative discipline strategies.", difficulty: 4, category: "Child & Family Services", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1242", stem: "What is the 'window of tolerance' concept in trauma-informed care?", options: ["A time limit for therapy sessions", "The optimal zone of arousal in which a person can effectively process information and respond to demands, with trauma survivors often having a narrowed window that results in hyperarousal (fight/flight) or hypoarousal (freeze/collapse) responses when overwhelmed", "A building safety feature", "A medication dosage range"], correctIndex: 1, rationale: "The window of tolerance (Siegel) is central to trauma-informed practice. Trauma narrows this window, making individuals more vulnerable to hyperarousal (anxiety, rage, hypervigilance) or hypoarousal (numbing, dissociation, collapse). Treatment aims to widen the window through regulation skills and gradual exposure.", difficulty: 3, category: "Trauma-Informed Care", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1243", stem: "A social worker is working with an adolescent who is self-harming through cutting. The FIRST clinical priority is:", options: ["Demanding the client stop immediately", "Conducting a comprehensive safety assessment to determine lethality risk, understanding the function of the self-harm behavior, providing psychoeducation, developing a safety plan with alternative coping strategies, and involving caregivers appropriately", "Hospitalizing the adolescent", "Ignoring the behavior to avoid reinforcing it"], correctIndex: 1, rationale: "Non-suicidal self-injury requires assessment of function (emotion regulation, communication, self-punishment), lethality risk, and co-occurring conditions. Safety planning, alternative coping skills (from DBT distress tolerance), and collaborative engagement are more effective than ultimatums or avoidance.", difficulty: 3, category: "Crisis Intervention", topic: "DSM-5 diagnoses", questionType: "PRIORITIZATION" },
  { id: "sw-1244", stem: "In family therapy, what does 'enmeshment' describe?", options: ["A healthy close family", "A boundary disturbance characterized by excessive emotional closeness and involvement among family members, with blurred individual boundaries resulting in difficulty with autonomy, individual identity development, and independent decision-making", "A communication style", "A conflict resolution technique"], correctIndex: 1, rationale: "Enmeshment (Minuchin) describes diffuse boundaries between family members where emotional reactivity is high, individual autonomy is limited, and members have difficulty distinguishing their own feelings from others'. It contrasts with both disengagement (rigid boundaries) and healthy connectedness (clear boundaries).", difficulty: 2, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1245", stem: "A social worker is conducting a capacity evaluation for an elderly client with early-stage dementia who wants to remain in an unsafe living situation. Which factors should be assessed?", options: ["Only the medical diagnosis", "The client's ability to understand relevant information, appreciate the consequences of their decision, reason about options, and communicate a consistent choice, recognizing that a diagnosis alone does not determine capacity and that capacity is decision-specific", "The family's preference only", "The client's financial resources"], correctIndex: 1, rationale: "Capacity assessment evaluates four functional abilities: understanding, appreciation, reasoning, and expressing a choice. Capacity is decision-specific (a person may have capacity for some decisions but not others) and can fluctuate. A diagnosis of dementia does not automatically equal incapacity.", difficulty: 4, category: "Assessment & Intervention Planning", topic: "elder abuse", questionType: "CASE_VIGNETTE" },
  { id: "sw-1246", stem: "What is 'secondary traumatic stress' and how does it differ from burnout?", options: ["They are identical concepts", "Secondary traumatic stress results from indirect exposure to trauma through working with traumatized clients and involves PTSD-like symptoms (intrusive thoughts, avoidance, hyperarousal), while burnout develops gradually from cumulative workplace stress and involves emotional exhaustion, depersonalization, and reduced accomplishment", "Only affects new social workers", "A sign of professional weakness"], correctIndex: 1, rationale: "Secondary traumatic stress (Figley) involves PTSD-like symptoms from indirect trauma exposure and can develop suddenly, while burnout (Maslach) develops gradually from chronic workplace stress. Both affect social workers but require different prevention and intervention strategies.", difficulty: 3, category: "Trauma-Informed Care", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1247", stem: "A social worker is working with a client whose cultural background emphasizes family decision-making over individual autonomy. How should the worker navigate informed consent?", options: ["Insist on individual consent only", "Respect the client's cultural framework for decision-making by exploring their preference for family involvement while ensuring the client's individual rights are protected and that consent is truly voluntary and informed", "Obtain consent from the family leader instead", "Skip informed consent due to cultural differences"], correctIndex: 1, rationale: "Culturally responsive informed consent respects collectivist decision-making frameworks while ensuring the individual's rights are protected. The social worker should explore the client's preference for family involvement, facilitate family discussion if desired, and confirm the client's voluntary agreement.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "APPLIED_ETHICS" },
  { id: "sw-1248", stem: "What is the difference between a 'process group' and a 'psychoeducational group' in clinical social work?", options: ["They are identical", "A process group focuses on interpersonal dynamics and here-and-now interactions among members as the primary therapeutic vehicle, while a psychoeducational group emphasizes structured teaching of specific content, skills, and information to achieve predetermined learning objectives", "Process groups are more effective", "Psychoeducational groups don't require a leader"], correctIndex: 1, rationale: "Process groups use group dynamics and interpersonal interactions as the primary change mechanism, with less structured content. Psychoeducational groups deliver structured curricula focused on knowledge and skill acquisition. Both serve important clinical purposes but differ in goals, structure, and therapeutic mechanisms.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1249", stem: "A social worker suspects that a client is experiencing intimate partner violence but the client denies it. The MOST appropriate approach is:", options: ["Accept the denial and move on", "Create a safe, nonjudgmental environment, provide information about domestic violence resources, use screening questions sensitively, respect the client's readiness for disclosure, and document observations while maintaining the therapeutic relationship", "Confront the client with evidence", "Report to law enforcement without the client's consent"], correctIndex: 1, rationale: "Intimate partner violence disclosure requires safety, trust, and client readiness. The social worker should use validated screening tools, create opportunities for disclosure, provide information about resources, plan for safety, and respect the client's autonomy while documenting concerns.", difficulty: 3, category: "Crisis Intervention", topic: "ethical dilemmas", questionType: "CASE_VIGNETTE" },
  { id: "sw-1250", stem: "In the DSM-5, what distinguishes bipolar I disorder from bipolar II disorder?", options: ["Bipolar II is less serious", "Bipolar I requires at least one manic episode (lasting at least 7 days or requiring hospitalization), while bipolar II involves at least one hypomanic episode (at least 4 days) and at least one major depressive episode, without a full manic episode", "Only bipolar I involves depression", "They respond to different medications"], correctIndex: 1, rationale: "The key distinction is episode severity: bipolar I includes full manic episodes (marked impairment, possible psychosis, hospitalization) while bipolar II involves hypomanic episodes (less severe, no psychosis, no hospitalization required). Bipolar II is not 'milder'—it often involves more time in depression and significant impairment.", difficulty: 3, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "MCQ" },
  { id: "sw-1251", stem: "A social worker is providing therapy to a child who witnessed domestic violence. Which play therapy technique is MOST appropriate?", options: ["Direct questioning about the violence", "Using nondirective play therapy to allow the child to express and process traumatic experiences through the natural language of play, observing themes, facilitating mastery, and providing a safe therapeutic space for emotional expression", "Adult talk therapy", "Ignoring the exposure"], correctIndex: 1, rationale: "Play therapy is developmentally appropriate for children who lack the verbal capacity for traditional talk therapy. Through play, children express traumatic experiences, work through feelings, develop coping strategies, and achieve mastery over overwhelming experiences in a safe therapeutic context.", difficulty: 2, category: "Trauma-Informed Care", topic: "child protection", questionType: "CASE_VIGNETTE" },
  { id: "sw-1252", stem: "What is the 'stages of change' (transtheoretical) model in substance use treatment?", options: ["A single stage of recovery", "A model identifying five stages—precontemplation, contemplation, preparation, action, and maintenance—through which individuals progress when changing behavior, with each stage requiring different interventions and recognizing that relapse is a common part of the change process", "Only applicable to smoking cessation", "A linear progression without setbacks"], correctIndex: 1, rationale: "The transtheoretical model (Prochaska & DiClemente) identifies readiness for change along a continuum. Matching interventions to stage increases effectiveness: consciousness raising in precontemplation, decisional balance in contemplation, planning in preparation, reinforcement in action, and relapse prevention in maintenance.", difficulty: 1, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "MCQ" },
  { id: "sw-1253", stem: "A social worker is asked by a court to provide a custody evaluation for a family they have been treating therapeutically. The MOST ethical response is:", options: ["Accept the request to help the family", "Decline the forensic evaluation role because serving as both therapist and evaluator creates a dual relationship that compromises objectivity and the therapeutic alliance, and recommend an independent forensic evaluator", "Provide the evaluation to save the family money", "Only evaluate the parent they have been treating"], correctIndex: 1, rationale: "Serving as both therapist and forensic evaluator is a prohibited dual relationship. The therapeutic role requires advocacy and alliance, while the evaluator role requires objectivity and impartiality. These roles are fundamentally incompatible, and mixing them harms both the therapeutic relationship and the evaluation's integrity.", difficulty: 4, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1254", stem: "What is 'mentalization' and its relevance to clinical social work?", options: ["A meditation technique", "The capacity to understand behavior in terms of underlying mental states (thoughts, feelings, intentions, desires) in oneself and others, which is often disrupted by trauma and attachment insecurity and is a key treatment target in mentalization-based therapy (MBT)", "A memory exercise", "Only relevant to autism spectrum disorder"], correctIndex: 1, rationale: "Mentalization (Fonagy) is the ability to interpret behavior as driven by mental states. It develops through secure attachment and is often impaired in individuals with personality disorders and trauma histories. MBT aims to improve mentalizing capacity, enhancing interpersonal functioning and emotion regulation.", difficulty: 4, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1255", stem: "A social worker is working with a refugee family experiencing acculturation stress. Which assessment consideration is MOST important?", options: ["Focusing only on immigration status", "Evaluating the family's pre-migration trauma exposure, migration journey experiences, and post-migration stressors including cultural adjustment, language barriers, discrimination, loss of social status, family role changes, and the intergenerational differences in acculturation pace", "Applying standard Western assessments", "Assessing only the children's adjustment"], correctIndex: 1, rationale: "Refugee families face a unique constellation of stressors across three phases: pre-migration (war, persecution, loss), migration (dangerous journeys, camps), and post-migration (acculturation, discrimination, poverty). Comprehensive assessment must address all phases and the differential acculturation rates within families.", difficulty: 3, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "CASE_VIGNETTE" },
  { id: "sw-1256", stem: "In cognitive behavioral therapy, what is 'exposure therapy' used for?", options: ["Exposing clients to criticism", "A systematic, evidence-based technique for treating anxiety disorders and PTSD by gradually and repeatedly exposing clients to feared stimuli in a safe environment, allowing habituation and the development of new, non-threatening associations", "Only for phobias", "A punitive intervention"], correctIndex: 1, rationale: "Exposure therapy is one of the most evidence-based interventions for anxiety and trauma-related disorders. It works through habituation and inhibitory learning, where repeated exposure to feared stimuli without negative consequences creates new safety associations that compete with the fear response.", difficulty: 2, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1257", stem: "A social worker discovers that a nursing home is systematically underreporting incidents of resident abuse. The social worker should:", options: ["Ignore it to avoid conflict", "Report the systemic abuse to the appropriate regulatory agencies (state long-term care ombudsman, adult protective services, licensing authorities), document findings, and advocate for the residents' safety and rights", "Only tell the facility administrator", "Wait for a specific resident complaint"], correctIndex: 1, rationale: "Systemic underreporting of abuse in long-term care facilities constitutes institutional abuse. Social workers have ethical and legal obligations to report to regulatory authorities, advocate for vulnerable residents, and pursue systemic change to protect current and future residents.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "elder abuse", questionType: "APPLIED_ETHICS" },
  { id: "sw-1258", stem: "What is 'narrative therapy' and its key concepts?", options: ["Simply telling stories", "A postmodern therapeutic approach that views problems as separate from people, using techniques like externalization, unique outcomes, re-authoring, and definitional ceremonies to help clients develop preferred narratives about their lives and identities", "A type of psychoanalysis", "Only for children"], correctIndex: 1, rationale: "Narrative therapy (White & Epston) separates people from problems ('the person is not the problem; the problem is the problem'), explores how dominant cultural narratives shape identity, and helps clients identify and amplify alternative stories that align with their preferred values and identity.", difficulty: 3, category: "Clinical Practice", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1259", stem: "A social worker is treating a client with severe depression who reports passive suicidal ideation but denies plan or intent. The MOST appropriate response is:", options: ["Immediately hospitalize the client", "Conduct a thorough suicide risk assessment, develop a collaborative safety plan, increase session frequency, consider psychiatric consultation for medication evaluation, identify protective factors, and ensure the client has crisis resources", "Ignore passive ideation as low risk", "Terminate therapy and refer elsewhere"], correctIndex: 1, rationale: "Passive suicidal ideation requires careful assessment and intervention. While not as immediately dangerous as active ideation with a plan, it indicates significant suffering and risk that warrants comprehensive assessment, safety planning, intensified treatment, and monitoring for escalation.", difficulty: 3, category: "Crisis Intervention", topic: "DSM-5 diagnoses", questionType: "CASE_VIGNETTE" },
  { id: "sw-1260", stem: "What is 'Milan systemic family therapy' known for?", options: ["Direct behavioral interventions", "A strategic approach to family therapy characterized by circular questioning, hypothesizing, neutrality, positive connotation of symptoms, and paradoxical interventions, with the therapy team observing sessions and providing end-of-session interventions", "Only individual therapy", "Psychoeducation only"], correctIndex: 1, rationale: "Milan systemic therapy (Selvini Palazzoli) uses circular questions to explore relational patterns, maintains therapeutic neutrality, reframes symptoms positively within the system's logic, and employs paradoxical prescriptions. The reflecting team approach enhances the systemic perspective.", difficulty: 5, category: "Clinical Practice", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1261", stem: "A social worker is working with a transgender client who has been denied healthcare. What is the social worker's PRIMARY role?", options: ["Providing medical advice", "Advocating for the client's access to affirming healthcare, connecting them with trans-competent providers, addressing discrimination, providing emotional support, and ensuring their rights are protected under applicable nondiscrimination policies", "Questioning the client's gender identity", "Referring to conversion therapy"], correctIndex: 1, rationale: "Social workers have an ethical obligation to advocate for equitable healthcare access for transgender individuals. This includes connecting clients with affirming providers, addressing systemic discrimination, providing supportive counseling, and advocating at policy levels for inclusive healthcare coverage.", difficulty: 2, category: "Diversity, Equity & Inclusion", topic: "cultural competency", questionType: "APPLIED_ETHICS" },
  { id: "sw-1262", stem: "What is 'splitting' as a defense mechanism?", options: ["Dividing possessions in divorce", "An unconscious defense mechanism in which an individual perceives people and situations in all-or-nothing terms, alternating between idealization and devaluation without integrating positive and negative qualities, commonly seen in borderline personality organization", "A therapy technique", "Separating children from parents"], correctIndex: 1, rationale: "Splitting is a primitive defense mechanism (Klein, Kernberg) where individuals cannot hold ambivalent feelings about the same person, vacillating between idealization ('all good') and devaluation ('all bad'). It is a hallmark of borderline personality organization and can significantly impact the therapeutic relationship.", difficulty: 3, category: "Clinical Practice", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1263", stem: "A social worker receives a gift from a grateful client at termination. The MOST appropriate response is:", options: ["Always accept to avoid offending the client", "Consider the cultural context, the gift's value, the therapeutic relationship dynamics, agency policy, and whether accepting might create an obligation, discussing the meaning of the gesture while making a thoughtful decision that prioritizes the client's welfare", "Always refuse without discussion", "Accept and reciprocate"], correctIndex: 1, rationale: "Gift-giving at termination requires nuanced consideration of cultural norms, monetary value, symbolic meaning, power dynamics, and agency policy. A blanket refusal may be culturally insensitive or therapeutically harmful, while automatic acceptance may cross boundaries. The meaning behind the gesture should be explored.", difficulty: 3, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "ETHICS_SCENARIO" },
  { id: "sw-1264", stem: "In Piaget's cognitive development theory, the 'formal operational' stage is characterized by:", options: ["Sensory exploration of objects", "The ability to think abstractly, hypothetically, and systematically, including deductive reasoning, considering multiple variables, and imagining possibilities beyond concrete reality, typically emerging around age 11-12", "Learning through imitation only", "Egocentric thinking"], correctIndex: 1, rationale: "Piaget's formal operational stage (approximately age 11+) marks the development of abstract reasoning, hypothetical thinking, and systematic problem-solving. Understanding this stage helps social workers set appropriate expectations for adolescent decision-making capacity and design age-appropriate interventions.", difficulty: 1, category: "Human Development", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1265", stem: "A social worker is facilitating a support group for parents of children with autism spectrum disorder. One parent expresses interest in an unproven 'cure.' The BEST response is:", options: ["Endorse the treatment to be supportive", "Empathize with the parent's desire to help their child, provide information about evidence-based interventions, gently address the risks of unproven treatments, and connect the family with reliable resources while respecting their decision-making autonomy", "Criticize the parent publicly", "Ignore the comment"], correctIndex: 1, rationale: "Parents of children with disabilities are vulnerable to unproven treatments. The social worker should validate the parent's motivation, provide accurate evidence-based information, discuss potential risks of unproven approaches, and respect autonomy while fulfilling the duty to inform.", difficulty: 3, category: "Child & Family Services", topic: "ethical dilemmas", questionType: "CASE_VIGNETTE" },
  { id: "sw-1266", stem: "What is 'vicarious traumatization' and how does it differ from secondary traumatic stress?", options: ["They are identical", "Vicarious traumatization refers to the cumulative, permanent transformation of the clinician's inner experience—including worldview, spirituality, identity, and cognitive schemas—resulting from empathic engagement with traumatized clients, while secondary traumatic stress involves more acute PTSD-like symptoms", "Only affects inexperienced clinicians", "A myth with no evidence"], correctIndex: 1, rationale: "Vicarious traumatization (Pearlman & Saakvitne) involves deep, cumulative shifts in the clinician's cognitive schemas about safety, trust, esteem, intimacy, and control. It is more pervasive than STS, affecting worldview and meaning systems. Both require proactive prevention strategies.", difficulty: 4, category: "Trauma-Informed Care", topic: "psychodynamic theory", questionType: "MCQ" },
  { id: "sw-1267", stem: "A social worker is working with a couple where one partner has recently disclosed a gambling addiction. The FIRST intervention should be:", options: ["Immediately separate the couple", "Assess the full scope of the gambling behavior and its financial, relational, and emotional impact on both partners, evaluate safety concerns, and begin stabilization through psychoeducation about gambling disorder and development of a harm reduction or abstinence plan", "Focus only on the non-gambling partner", "Refer exclusively to Gamblers Anonymous"], correctIndex: 1, rationale: "Gambling disorder assessment must evaluate severity, financial impact, co-occurring conditions, relationship damage, and safety (suicidality is elevated in gambling disorder). Initial intervention stabilizes the crisis, provides psychoeducation, and engages both partners in understanding the disorder and its systemic impact.", difficulty: 3, category: "Addictions & Substance Use", topic: "substance use disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-1268", stem: "What is the 'person-in-environment' (PIE) perspective unique to social work?", options: ["Only environmental advocacy", "A foundational social work framework that emphasizes understanding individuals within the context of their social environments—including family, community, cultural, institutional, and societal systems—and recognizing the reciprocal interactions between personal functioning and environmental conditions", "A purely ecological theory", "A medical model approach"], correctIndex: 1, rationale: "PIE is the signature perspective of social work, distinguishing it from other helping professions. It guides assessment and intervention by considering the dynamic interplay between the person (biological, psychological, spiritual) and their environment (social, economic, political, cultural), avoiding reductionist approaches.", difficulty: 1, category: "Assessment & Intervention Planning", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1269", stem: "A social worker is working with an elderly client who exhibits signs of depression but attributes their symptoms to 'just getting old.' The MOST appropriate response is:", options: ["Agree that it's normal aging", "Gently challenge the normalization of depressive symptoms in older adults by providing psychoeducation that depression is not a normal part of aging, exploring symptoms that may be masked as somatic complaints, and offering evidence-based treatment options", "Only focus on physical health", "Refer to a geriatrician without discussing mental health"], correctIndex: 1, rationale: "Depression in older adults is often underdiagnosed because symptoms may be attributed to normal aging, medical conditions, or expressed as somatic complaints. Social workers play a critical role in psychoeducation, destigmatizing mental health treatment, and ensuring older adults access appropriate care.", difficulty: 2, category: "Mental Health & Psychopathology", topic: "DSM-5 diagnoses", questionType: "CASE_VIGNETTE" },
  { id: "sw-1270", stem: "In trauma-informed care, what does 'retraumatization' mean and how can it be prevented?", options: ["Experiencing a new trauma", "The re-experiencing of traumatic stress responses triggered by situations, interactions, or environments that mirror or remind the individual of the original trauma, which can be prevented through trauma-sensitive organizational practices, informed consent, predictability, and client empowerment", "Only occurs in therapy", "An unavoidable part of treatment"], correctIndex: 1, rationale: "Retraumatization occurs when systems or interactions inadvertently replicate dynamics of the original trauma (loss of control, helplessness, lack of voice). Prevention requires trauma-informed organizational policies, staff training, transparent procedures, choice and collaboration, and attention to physical environments.", difficulty: 2, category: "Trauma-Informed Care", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1271", stem: "A social worker is facilitating a family session where an adolescent reveals substance use. The parents react with anger. The social worker should:", options: ["Side with the parents' anger", "Validate the parents' concern while de-escalating the emotional intensity, reframe the disclosure as a courageous step, facilitate constructive dialogue, and help the family develop a collaborative plan that maintains the adolescent's engagement", "End the session immediately", "Minimize the substance use to calm the parents"], correctIndex: 1, rationale: "When substance use is disclosed in family therapy, the social worker must manage multiple emotional responses. Validating parental concern while protecting the adolescent's therapeutic engagement, de-escalating reactivity, and facilitating constructive dialogue prevents the session from becoming punitive and maintains the family's capacity for problem-solving.", difficulty: 3, category: "Child & Family Services", topic: "substance use disorders", questionType: "CASE_VIGNETTE" },
  { id: "sw-1272", stem: "What is 'confirmation bias' and why is it relevant to social work assessment?", options: ["A legal term", "The tendency to search for, interpret, and recall information in ways that confirm pre-existing beliefs or hypotheses, which can lead social workers to overlook important assessment data that contradicts their initial impressions and result in inaccurate clinical formulations", "Only relevant to research", "A type of cognitive distortion in clients"], correctIndex: 1, rationale: "Confirmation bias in social work assessment can lead to premature diagnostic conclusions, missed safety concerns, and culturally biased interpretations. Social workers must actively seek disconfirming evidence, use structured assessment tools, consult with colleagues, and remain open to revising initial hypotheses.", difficulty: 3, category: "Assessment & Intervention Planning", topic: "cognitive behavioral therapy", questionType: "MCQ" },
  { id: "sw-1273", stem: "A social worker is providing crisis counseling to a survivor of sexual assault. The MOST important initial intervention is:", options: ["Pressing for a detailed account of the assault", "Ensuring the survivor's immediate physical and emotional safety, providing supportive presence, explaining options (medical exam, reporting) without pressuring decisions, and restoring a sense of control by empowering the survivor to make their own choices about next steps", "Encouraging immediate forgiveness", "Focusing on what the survivor could have done differently"], correctIndex: 1, rationale: "Crisis intervention with sexual assault survivors prioritizes safety, empowerment, and client control. Restoring a sense of autonomy is therapeutically critical because assault involves loss of control. The social worker provides information and options while respecting the survivor's pace and decisions.", difficulty: 2, category: "Crisis Intervention", topic: "ethical dilemmas", questionType: "CASE_VIGNETTE" },
  { id: "sw-1274", stem: "What is 'the Duluth Model' for domestic violence intervention?", options: ["A couples therapy approach", "A coordinated community response to domestic violence that centers the Power and Control Wheel, frames abuse as a pattern of coercive control rooted in patriarchal beliefs, uses batterer intervention programs to promote accountability, and coordinates between justice and victim services", "A medical treatment model", "A child welfare framework"], correctIndex: 1, rationale: "The Duluth Model views domestic violence as rooted in the abuser's desire for power and control, informed by societal patriarchal norms. It uses the Power and Control Wheel to illustrate abuse tactics, emphasizes batterer accountability, coordinates community response, and avoids couples counseling as inappropriate for violent relationships.", difficulty: 3, category: "Crisis Intervention", topic: "family systems", questionType: "MCQ" },
  { id: "sw-1275", stem: "A social worker is terminating services with a long-term client. Which consideration is MOST important for an ethical and clinically appropriate termination?", options: ["Ending abruptly to avoid dependency", "Planning termination well in advance, processing the ending within the therapeutic relationship, reviewing progress and remaining goals, ensuring continuity of care through appropriate referrals, and addressing the client's feelings about loss and ending while honoring the therapeutic relationship", "Maintaining contact through social media", "Extending treatment indefinitely to avoid termination feelings"], correctIndex: 1, rationale: "Ethical termination requires adequate notice, processing feelings about ending (which may mirror past losses), reviewing therapeutic gains, planning for maintenance and future needs, providing referrals for ongoing support, and honoring the significance of the therapeutic relationship. Abrupt or poorly planned termination can be harmful.", difficulty: 2, category: "Ethics & Professional Boundaries", topic: "ethical dilemmas", questionType: "APPLIED_ETHICS" }
];
